import java.util.*; public class Three{ public static void main(String[] args){ Set<Integer> s1=new HashSet<>(Arrays.asList(1,2,3,4)); Set<Integer> s2=new HashSet<>(Arrays.asList(3,4,5,6)); Set<Integer> u=new HashSet<>(s1); u.addAll(s2); Set<Integer> i=new HashSet<>(s1); i.retainAll(s2); Set<Integer> d=new HashSet<>(s1); d.removeAll(s2); System.out.println("Union "+u); System.out.println("Intersection "+i); System.out.println("Difference "+d); }}